import React, { useState, useEffect } from "react";
import { fetchInvoices, deleteInvoice } from "./api";

const API_URL = "http://127.0.0.1:8000";

export default function InvoiceExtractor() {
  const [invoices, setInvoices] = useState([]);

  useEffect(() => {
    fetchInvoices().then(data => setInvoices(data.invoices));
  }, []);

  return (
    <div>
      <h2>Invoices</h2>
      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Filename</th>
            <th>Amount</th>
            <th>Date</th>
            <th>Order #</th>
            <th>Merchant</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {invoices.map((invoice) => (
            <tr key={invoice.id}>
              <td>{invoice.id}</td>
              <td>{invoice.filename}</td>
              <td>${invoice.amount}</td>
              <td>{invoice.date}</td>
              <td>{invoice.order_number}</td>
              <td>{invoice.merchant}</td>
              <td>
                <button onClick={() => deleteInvoice(invoice.id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
